CREATE TABLE IF NOT EXISTS privacy_monitoring_controls(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,control_key text NOT NULL,name text NOT NULL,frequency text NOT NULL,owner text NOT NULL DEFAULT '',enabled boolean NOT NULL DEFAULT true,last_run_at timestamptz,next_run_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,control_key));
CREATE TABLE IF NOT EXISTS privacy_monitoring_runs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,control_id uuid NOT NULL REFERENCES privacy_monitoring_controls(id),status text NOT NULL DEFAULT 'running',started_at timestamptz NOT NULL,completed_at timestamptz,result jsonb NOT NULL DEFAULT '{}'::jsonb,failure_reason text NOT NULL DEFAULT '',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS privacy_monitoring_alerts(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,control_id uuid NOT NULL REFERENCES privacy_monitoring_controls(id),run_id uuid NOT NULL REFERENCES privacy_monitoring_runs(id),message text NOT NULL,severity text NOT NULL DEFAULT 'high',status text NOT NULL DEFAULT 'open',assignee text NOT NULL DEFAULT '',acknowledged_at timestamptz,resolved_at timestamptz,resolution text NOT NULL DEFAULT '',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_privacy_monitoring_alerts ON privacy_monitoring_alerts(tenant_id,status,severity);
